import{_ as s,c as a,a as e,o as t}from"./app-CFgUeV5-.js";const p={};function l(i,n){return t(),a("div",null,n[0]||(n[0]=[e(`<h2 id="spring、springboot-的常用注解" tabindex="-1"><a class="header-anchor" href="#spring、springboot-的常用注解"><span>Spring、SpringBoot 的常用注解？</span></a></h2><p><strong>回答：</strong></p><h3 id="_1-核心容器注解" tabindex="-1"><a class="header-anchor" href="#_1-核心容器注解"><span><strong>1. 核心容器注解</strong></span></a></h3><ol><li><p><strong>组件扫描与 Bean 定义</strong></p><ul><li><code>@Component</code>：通用组件注解，标记类为 Spring Bean</li><li><code>@Repository</code>：DAO 层组件，提供数据访问异常转换</li><li><code>@Service</code>：服务层组件，标记业务逻辑类</li><li><code>@Controller</code>：控制器层组件，标记 Web 控制器</li><li><code>@Configuration</code>：配置类，替代 XML 配置文件</li><li><code>@Bean</code>：声明 Bean 方法，通常在 <code>@Configuration</code> 类中使用</li><li><code>@ComponentScan</code>：指定扫描路径，自动发现组件</li><li><code>@Import</code>：导入其他配置类或组件</li></ul></li><li><p><strong>依赖注入</strong></p><ul><li><code>@Autowired</code>：按类型自动注入依赖</li><li><code>@Qualifier</code>：与 <code>@Autowired</code> 配合，按名称指定注入 Bean</li><li><code>@Resource</code>：JSR-250 标准注解，按名称或类型注入</li><li><code>@Value</code>：注入配置文件中的值（如 <code>application.properties</code>）</li><li><code>@Required</code>：标记 Bean 属性为必需，初始化时检查</li></ul></li><li><p><strong>作用域与生命周期</strong></p><ul><li><code>@Scope</code>：指定 Bean 的作用域（如 <code>singleton</code>, <code>prototype</code>）</li><li><code>@Lazy</code>：延迟初始化 Bean</li><li><code>@PostConstruct</code>：Bean 初始化后执行的方法</li><li><code>@PreDestroy</code>：Bean 销毁前执行的方法</li></ul></li></ol><h4 id="_2-aop-注解" tabindex="-1"><a class="header-anchor" href="#_2-aop-注解"><span><strong>2. AOP 注解</strong></span></a></h4><ol><li><p><strong>切面定义</strong></p><ul><li><code>@Aspect</code>：标记切面类</li><li><code>@Pointcut</code>：定义切入点表达式</li><li><code>@Order</code>：指定切面执行顺序</li></ul></li><li><p><strong>通知类型</strong></p><ul><li><code>@Before</code>：前置通知</li><li><code>@After</code>：后置通知（无论是否异常）</li><li><code>@AfterReturning</code>：返回通知（方法正常返回后）</li><li><code>@AfterThrowing</code>：异常通知（方法抛出异常时）</li><li><code>@Around</code>：环绕通知，可控制方法执行</li></ul></li></ol><h3 id="_3-事务管理注解" tabindex="-1"><a class="header-anchor" href="#_3-事务管理注解"><span><strong>3. 事务管理注解</strong></span></a></h3><ul><li><code>@Transactional</code>：声明事务属性，支持隔离级别、传播行为等配置</li><li><code>@EnableTransactionManagement</code>：启用声明式事务支持</li></ul><h3 id="_4-spring-mvc-注解" tabindex="-1"><a class="header-anchor" href="#_4-spring-mvc-注解"><span><strong>4. Spring MVC 注解</strong></span></a></h3><ol><li><p><strong>控制器与请求处理</strong></p><ul><li><code>@RestController</code>：组合 <code>@Controller</code> 和 <code>@ResponseBody</code>，返回 JSON/XML</li><li><code>@RequestMapping</code>：映射请求路径和 HTTP 方法</li><li><code>@GetMapping</code>、<code>@PostMapping</code> 等：简化的请求映射注解</li><li><code>@RequestBody</code>：将请求体解析为对象</li><li><code>@ResponseBody</code>：将返回值直接作为响应体</li><li><code>@PathVariable</code>：获取路径变量</li><li><code>@RequestParam</code>：获取请求参数</li><li><code>@RequestHeader</code>：获取请求头</li><li><code>@CookieValue</code>：获取 Cookie 值</li><li><code>@ModelAttribute</code>：将请求参数绑定到模型</li><li><code>@SessionAttributes</code>：将模型属性存储在会话中</li></ul></li><li><p><strong>异常处理</strong></p><ul><li><code>@ExceptionHandler</code>：处理控制器内的异常</li><li><code>@ControllerAdvice</code>：全局异常处理类</li><li><code>@RestControllerAdvice</code>：组合 <code>@ControllerAdvice</code> 和 <code>@ResponseBody</code></li></ul></li></ol><h3 id="spring-boot-常用注解" tabindex="-1"><a class="header-anchor" href="#spring-boot-常用注解"><span>Spring Boot 常用注解</span></a></h3><h4 id="_1-启动与自动配置" tabindex="-1"><a class="header-anchor" href="#_1-启动与自动配置"><span><strong>1. 启动与自动配置</strong></span></a></h4><ul><li><code>@SpringBootApplication</code>：组合 <code>@Configuration</code>、<code>@EnableAutoConfiguration</code> 和 <code>@ComponentScan</code>，标记主应用类</li><li><code>@EnableAutoConfiguration</code>：启用 Spring Boot 的自动配置机制</li><li><code>@SpringBootTest</code>：Spring Boot 集成测试注解</li><li><code>@AutoConfigureMockMvc</code>：自动配置 MockMvc 进行 Web 测试</li></ul><h4 id="_2-配置属性绑定" tabindex="-1"><a class="header-anchor" href="#_2-配置属性绑定"><span><strong>2. 配置属性绑定</strong></span></a></h4><ul><li><code>@ConfigurationProperties</code>：将配置文件属性绑定到 Bean</li><li><code>@EnableConfigurationProperties</code>：启用 <code>@ConfigurationProperties</code> 注解的 Bean</li><li><code>@PropertySource</code>：加载自定义属性文件</li><li><code>@Value</code>：获取单个配置值</li></ul><h4 id="_3-其他增强注解" tabindex="-1"><a class="header-anchor" href="#_3-其他增强注解"><span><strong>3. 其他增强注解</strong></span></a></h4><ul><li><code>@WebMvcTest</code>：只测试 Spring MVC 组件，不启动完整应用</li><li><code>@DataJpaTest</code>：只测试 JPA 组件，不启动完整应用</li><li><code>@TestConfiguration</code>：测试专用配置类</li><li><code>@MockBean</code>：在测试中替换 Bean 为 Mock 对象</li><li><code>@TestPropertySource</code>：测试环境专用配置</li><li><code>@RefreshScope</code>：配置刷新时重新创建 Bean（用于配置中心）</li></ul><h2 id="什么是-spring-它有哪些核心模块" tabindex="-1"><a class="header-anchor" href="#什么是-spring-它有哪些核心模块"><span>什么是 Spring？它有哪些核心模块？</span></a></h2><p><strong>回答：</strong> Spring 是一个轻量级的 Java 开发框架，核心模块包括：</p><ul><li>Spring Core（IOC 容器）</li><li>Spring AOP（面向切面编程）</li><li>Spring MVC（Web 框架）</li><li>Spring Data、Spring Security 等</li></ul><h2 id="什么是-ioc-和-aop" tabindex="-1"><a class="header-anchor" href="#什么是-ioc-和-aop"><span>什么是 IOC 和 AOP？</span></a></h2><p><strong>回答：</strong></p><ul><li>IOC（控制反转）：对象创建与依赖注入由容器管理，降低耦合。</li><li>AOP（面向切面编程）：用来处理日志、事务等横切逻辑。</li></ul><h2 id="aop的常用的注解有哪些-实现原理" tabindex="-1"><a class="header-anchor" href="#aop的常用的注解有哪些-实现原理"><span>AOP的常用的注解有哪些？实现原理？</span></a></h2><p><strong>回答：</strong></p><h3 id="_1-常用注解" tabindex="-1"><a class="header-anchor" href="#_1-常用注解"><span><strong>1. 常用注解</strong></span></a></h3><p>Spring AOP 基于 AspectJ 注解提供了强大的面向切面编程支持，常用注解包括：</p><ol><li><p><strong>@Aspect</strong><br> 声明一个类为切面类，需配合 <code>@Component</code> 注解使用。</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java" data-title="java"><pre><code><span class="line"><span class="token annotation punctuation">@Aspect</span></span>
<span class="line"><span class="token annotation punctuation">@Component</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">LoggingAspect</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// 切面逻辑</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p><strong>@Pointcut</strong><br> 定义切入点表达式，指定在哪些方法执行时触发通知。</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java" data-title="java"><pre><code><span class="line"><span class="token annotation punctuation">@Pointcut</span><span class="token punctuation">(</span><span class="token string">&quot;execution(* com.example.service.*.*(..))&quot;</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">serviceMethods</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token punctuation">}</span> <span class="token comment">// 切入点签名</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p><strong>@Before</strong><br> 前置通知：在目标方法执行前执行。</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java" data-title="java"><pre><code><span class="line"><span class="token annotation punctuation">@Before</span><span class="token punctuation">(</span><span class="token string">&quot;serviceMethods()&quot;</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">beforeAdvice</span><span class="token punctuation">(</span><span class="token class-name">JoinPoint</span> joinPoint<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;Before method: &quot;</span> <span class="token operator">+</span> joinPoint<span class="token punctuation">.</span><span class="token function">getSignature</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">getName</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p><strong>@After</strong><br> 后置通知：无论目标方法是否抛出异常，都会执行。</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java" data-title="java"><pre><code><span class="line"><span class="token annotation punctuation">@After</span><span class="token punctuation">(</span><span class="token string">&quot;serviceMethods()&quot;</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">afterAdvice</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;After method execution&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p><strong>@AfterReturning</strong><br> 返回通知：在目标方法正常返回后执行，可获取返回值。</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java" data-title="java"><pre><code><span class="line"><span class="token annotation punctuation">@AfterReturning</span><span class="token punctuation">(</span>pointcut <span class="token operator">=</span> <span class="token string">&quot;serviceMethods()&quot;</span><span class="token punctuation">,</span> returning <span class="token operator">=</span> <span class="token string">&quot;result&quot;</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">afterReturningAdvice</span><span class="token punctuation">(</span><span class="token class-name">Object</span> result<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;Method returned: &quot;</span> <span class="token operator">+</span> result<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p><strong>@AfterThrowing</strong><br> 异常通知：在目标方法抛出异常时执行。</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java" data-title="java"><pre><code><span class="line"><span class="token annotation punctuation">@AfterThrowing</span><span class="token punctuation">(</span>pointcut <span class="token operator">=</span> <span class="token string">&quot;serviceMethods()&quot;</span><span class="token punctuation">,</span> throwing <span class="token operator">=</span> <span class="token string">&quot;ex&quot;</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">afterThrowingAdvice</span><span class="token punctuation">(</span><span class="token class-name">Exception</span> ex<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;Exception caught: &quot;</span> <span class="token operator">+</span> ex<span class="token punctuation">.</span><span class="token function">getMessage</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p><strong>@Around</strong><br> 环绕通知：环绕目标方法执行，可控制方法的执行时机和结果。</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java" data-title="java"><pre><code><span class="line"><span class="token annotation punctuation">@Around</span><span class="token punctuation">(</span><span class="token string">&quot;serviceMethods()&quot;</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token class-name">Object</span> <span class="token function">aroundAdvice</span><span class="token punctuation">(</span><span class="token class-name">ProceedingJoinPoint</span> joinPoint<span class="token punctuation">)</span> <span class="token keyword">throws</span> <span class="token class-name">Throwable</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;Before method proceed&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token class-name">Object</span> result <span class="token operator">=</span> joinPoint<span class="token punctuation">.</span><span class="token function">proceed</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 执行目标方法</span></span>
<span class="line">    <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;After method proceed&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token keyword">return</span> result<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p><strong>@Order</strong><br> 指定切面执行顺序，值越小优先级越高。</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java" data-title="java"><pre><code><span class="line"><span class="token annotation punctuation">@Aspect</span></span>
<span class="line"><span class="token annotation punctuation">@Component</span></span>
<span class="line"><span class="token annotation punctuation">@Order</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span> <span class="token comment">// 优先级高于 @Order(2) 的切面</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">TransactionAspect</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// ...</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li></ol><h3 id="_2-实现原理" tabindex="-1"><a class="header-anchor" href="#_2-实现原理"><span><strong>2. 实现原理</strong></span></a></h3><p>Spring AOP 基于<strong>代理模式</strong>实现，主要有两种代理方式：</p><ol><li><p><strong>JDK 动态代理</strong><br> 基于接口的代理，代理类实现目标接口。</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java" data-title="java"><pre><code><span class="line"><span class="token comment">// 示例接口</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">interface</span> <span class="token class-name">UserService</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">void</span> <span class="token function">createUser</span><span class="token punctuation">(</span><span class="token class-name">String</span> username<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// JDK 动态代理生成的代理类（简化）</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">class</span> $<span class="token class-name">Proxy0</span> <span class="token keyword">implements</span> <span class="token class-name">UserService</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">private</span> <span class="token class-name">UserService</span> target<span class="token punctuation">;</span></span>
<span class="line">    </span>
<span class="line">    <span class="token keyword">public</span> $<span class="token class-name">Proxy0</span><span class="token punctuation">(</span><span class="token class-name">UserService</span> target<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token keyword">this</span><span class="token punctuation">.</span>target <span class="token operator">=</span> target<span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line">    </span>
<span class="line">    <span class="token annotation punctuation">@Override</span></span>
<span class="line">    <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">createUser</span><span class="token punctuation">(</span><span class="token class-name">String</span> username<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token comment">// 前置通知</span></span>
<span class="line">        <span class="token function">beforeAdvice</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token keyword">try</span> <span class="token punctuation">{</span></span>
<span class="line">            target<span class="token punctuation">.</span><span class="token function">createUser</span><span class="token punctuation">(</span>username<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 执行目标方法</span></span>
<span class="line">            <span class="token comment">// 返回通知</span></span>
<span class="line">            <span class="token function">afterReturningAdvice</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token punctuation">}</span> <span class="token keyword">catch</span> <span class="token punctuation">(</span><span class="token class-name">Exception</span> e<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">            <span class="token comment">// 异常通知</span></span>
<span class="line">            <span class="token function">afterThrowingAdvice</span><span class="token punctuation">(</span>e<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token punctuation">}</span> <span class="token keyword">finally</span> <span class="token punctuation">{</span></span>
<span class="line">            <span class="token comment">// 后置通知</span></span>
<span class="line">            <span class="token function">afterAdvice</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token punctuation">}</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p><strong>CGLIB 代理</strong><br> 基于子类的代理，通过字节码生成技术创建目标类的子类。</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java" data-title="java"><pre><code><span class="line"><span class="token comment">// 示例类（无接口）</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">UserServiceImpl</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">createUser</span><span class="token punctuation">(</span><span class="token class-name">String</span> username<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token comment">// ...</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// CGLIB 生成的子类（简化）</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">UserServiceImpl</span>$$<span class="token class-name">EnhancerByCGLIB</span>$$ <span class="token keyword">extends</span> <span class="token class-name">UserServiceImpl</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">private</span> <span class="token class-name">MethodInterceptor</span> interceptor<span class="token punctuation">;</span></span>
<span class="line">    </span>
<span class="line">    <span class="token annotation punctuation">@Override</span></span>
<span class="line">    <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">createUser</span><span class="token punctuation">(</span><span class="token class-name">String</span> username<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token comment">// 调用拦截器，执行通知逻辑</span></span>
<span class="line">        interceptor<span class="token punctuation">.</span><span class="token function">intercept</span><span class="token punctuation">(</span><span class="token keyword">this</span><span class="token punctuation">,</span> method<span class="token punctuation">,</span> args<span class="token punctuation">,</span> methodProxy<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li></ol><h3 id="_3-aop-代理创建流程" tabindex="-1"><a class="header-anchor" href="#_3-aop-代理创建流程"><span><strong>3. AOP 代理创建流程</strong></span></a></h3><ol><li><p><strong>解析切面配置</strong><br> Spring 在启动时扫描带有 <code>@Aspect</code> 注解的类，解析其中的通知（Advice）和切入点（Pointcut）。</p></li><li><p><strong>创建 BeanPostProcessor</strong><br><code>AnnotationAwareAspectJAutoProxyCreator</code> 作为后置处理器，在 Bean 初始化后检查是否需要创建代理。</p></li><li><p><strong>匹配切入点</strong><br> 对每个 Bean 的方法进行切入点表达式匹配，若匹配则创建代理。</p></li><li><p><strong>生成代理对象</strong></p><ul><li>若目标类实现了接口，使用 JDK 动态代理。</li><li>若目标类未实现接口（或 <code>proxy-target-class=true</code>），使用 CGLIB 代理。</li></ul></li><li><p><strong>代理链调用</strong><br> 代理对象执行方法时，按顺序调用所有匹配的通知，最后调用目标方法。</p></li></ol><h3 id="_4-关键组件" tabindex="-1"><a class="header-anchor" href="#_4-关键组件"><span><strong>4. 关键组件</strong></span></a></h3><ol><li><p><strong>ProxyFactory</strong><br> 创建代理对象的工厂类，根据配置选择 JDK 或 CGLIB 代理。</p></li><li><p><strong>Advisor</strong><br> 包含一个通知（Advice）和一个切入点（Pointcut），定义何时何地执行通知。</p></li><li><p><strong>MethodInterceptor</strong><br> 拦截器接口，环绕通知通过实现该接口来控制方法的执行。</p></li><li><p><strong>JoinPoint</strong><br> 连接点，表示程序执行过程中的某个点（如方法调用），通知可通过它获取上下文信息。</p></li></ol><h3 id="_5-aop-vs-aspectj" tabindex="-1"><a class="header-anchor" href="#_5-aop-vs-aspectj"><span><strong>5. AOP vs AspectJ</strong></span></a></h3><p>Spring AOP 是基于代理的轻量级实现，而 AspectJ 是完整的 AOP 框架，支持：</p><ul><li><strong>编译时织入</strong>（Compile-time weaving）</li><li><strong>加载时织入</strong>（Load-time weaving）</li><li><strong>运行时织入</strong>（类似 Spring AOP）</li></ul><p>Spring AOP 仅支持运行时织入，而 AspectJ 功能更强大，但配置更复杂。</p><h2 id="spring-是如何实现依赖注入的-底层是如何实现的" tabindex="-1"><a class="header-anchor" href="#spring-是如何实现依赖注入的-底层是如何实现的"><span>Spring 是如何实现依赖注入的？底层是如何实现的？</span></a></h2><p><strong>回答：</strong></p><p>Spring 的依赖注入（Dependency Injection, DI） 是其核心特性之一，通过反射和 IoC（控制反转）容器实现对象间的松耦合。</p><h3 id="_1-依赖注入的基本概念" tabindex="-1"><a class="header-anchor" href="#_1-依赖注入的基本概念"><span><strong>1. 依赖注入的基本概念</strong></span></a></h3><ul><li><strong>依赖注入</strong>：对象的依赖由外部容器动态提供，对象仅通过接口或抽象类引用依赖。</li></ul><p><strong>示例</strong>：</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java" data-title="java"><pre><code><span class="line"><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">UserController</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">private</span> <span class="token class-name">UserService</span> userService<span class="token punctuation">;</span> <span class="token comment">// 依赖声明</span></span>
<span class="line">    </span>
<span class="line">    <span class="token comment">// 通过构造函数注入依赖（Constructor Injection）</span></span>
<span class="line">    <span class="token keyword">public</span> <span class="token class-name">UserController</span><span class="token punctuation">(</span><span class="token class-name">UserService</span> userService<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token keyword">this</span><span class="token punctuation">.</span>userService <span class="token operator">=</span> userService<span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2-spring-依赖注入的底层实现" tabindex="-1"><a class="header-anchor" href="#_2-spring-依赖注入的底层实现"><span><strong>2. Spring 依赖注入的底层实现</strong></span></a></h3><h4 id="_1-beandefinition-与-bean-元数据" tabindex="-1"><a class="header-anchor" href="#_1-beandefinition-与-bean-元数据"><span><strong>① BeanDefinition 与 Bean 元数据</strong></span></a></h4><ul><li><strong>BeanDefinition</strong>：Spring 容器在启动时解析配置（XML、注解或 Java 配置），将每个 Bean 的定义信息（如类名、作用域、依赖关系）封装为 <code>BeanDefinition</code> 对象。</li><li><strong>注册表</strong>：<code>BeanDefinitionRegistry</code> 存储所有 <code>BeanDefinition</code>，作为创建 Bean 的蓝图。</li></ul><p><strong>流程</strong>：</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java" data-title="java"><pre><code><span class="line"><span class="token comment">// 伪代码：Spring 解析 Bean 定义</span></span>
<span class="line"><span class="token class-name">BeanDefinition</span> bd <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">RootBeanDefinition</span><span class="token punctuation">(</span><span class="token class-name">UserServiceImpl</span><span class="token punctuation">.</span><span class="token keyword">class</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">bd<span class="token punctuation">.</span><span class="token function">setScope</span><span class="token punctuation">(</span><span class="token string">&quot;singleton&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">registry<span class="token punctuation">.</span><span class="token function">registerBeanDefinition</span><span class="token punctuation">(</span><span class="token string">&quot;userService&quot;</span><span class="token punctuation">,</span> bd<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-beanfactory-与反射创建对象" tabindex="-1"><a class="header-anchor" href="#_2-beanfactory-与反射创建对象"><span><strong>② BeanFactory 与反射创建对象</strong></span></a></h4><ul><li><strong>BeanFactory</strong>：Spring 的核心工厂接口，负责创建和管理 Bean。</li><li><strong>反射实例化</strong>：通过 Java 反射调用构造函数创建 Bean 实例。</li></ul><p><strong>示例</strong>：</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java" data-title="java"><pre><code><span class="line"><span class="token comment">// 伪代码：Spring 通过反射创建 Bean</span></span>
<span class="line"><span class="token class-name">Class</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token operator">?</span><span class="token punctuation">&gt;</span></span> beanClass <span class="token operator">=</span> <span class="token class-name">Class</span><span class="token punctuation">.</span><span class="token function">forName</span><span class="token punctuation">(</span>beanDefinition<span class="token punctuation">.</span><span class="token function">getClassName</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token class-name">Constructor</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token operator">?</span><span class="token punctuation">&gt;</span></span> constructor <span class="token operator">=</span> beanClass<span class="token punctuation">.</span><span class="token function">getDeclaredConstructor</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token class-name">Object</span> beanInstance <span class="token operator">=</span> constructor<span class="token punctuation">.</span><span class="token function">newInstance</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 反射创建实例</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_3-依赖解析与注入" tabindex="-1"><a class="header-anchor" href="#_3-依赖解析与注入"><span><strong>③ 依赖解析与注入</strong></span></a></h4><ul><li><strong>依赖查找</strong>：根据 <code>BeanDefinition</code> 中的依赖描述，从容器中查找匹配的 Bean。</li><li><strong>反射注入</strong>：通过反射设置字段值（Field Injection）或调用 setter 方法（Setter Injection）。</li></ul><p><strong>示例</strong>：</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java" data-title="java"><pre><code><span class="line"><span class="token comment">// 伪代码：Spring 通过反射注入依赖</span></span>
<span class="line"><span class="token class-name">Field</span> field <span class="token operator">=</span> beanClass<span class="token punctuation">.</span><span class="token function">getDeclaredField</span><span class="token punctuation">(</span><span class="token string">&quot;userService&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">field<span class="token punctuation">.</span><span class="token function">setAccessible</span><span class="token punctuation">(</span><span class="token boolean">true</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 打破 private 限制</span></span>
<span class="line">field<span class="token punctuation">.</span><span class="token function">set</span><span class="token punctuation">(</span>beanInstance<span class="token punctuation">,</span> userServiceBean<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 注入依赖</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_4-后置处理器-beanpostprocessor" tabindex="-1"><a class="header-anchor" href="#_4-后置处理器-beanpostprocessor"><span><strong>④ 后置处理器（BeanPostProcessor）</strong></span></a></h4><ul><li><strong>增强 Bean</strong>：允许在 Bean 实例化后、初始化前后进行自定义处理（如 AOP 代理）。</li><li><strong>常见实现</strong>：<code>AutowiredAnnotationBeanPostProcessor</code> 处理 <code>@Autowired</code> 注解。</li></ul><p><strong>示例</strong>：</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java" data-title="java"><pre><code><span class="line"><span class="token comment">// 伪代码：处理 @Autowired 注解</span></span>
<span class="line"><span class="token keyword">if</span> <span class="token punctuation">(</span>annotation <span class="token keyword">instanceof</span> <span class="token class-name">Autowired</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// 查找依赖 Bean</span></span>
<span class="line">    <span class="token class-name">Object</span> dependency <span class="token operator">=</span> beanFactory<span class="token punctuation">.</span><span class="token function">getBean</span><span class="token punctuation">(</span>dependencyType<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token comment">// 通过反射注入</span></span>
<span class="line">    field<span class="token punctuation">.</span><span class="token function">set</span><span class="token punctuation">(</span>bean<span class="token punctuation">,</span> dependency<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_3-注解驱动的依赖注入-autowired" tabindex="-1"><a class="header-anchor" href="#_3-注解驱动的依赖注入-autowired"><span><strong>3. 注解驱动的依赖注入（@Autowired）</strong></span></a></h3><p>当使用 <code>@Autowired</code> 注解时，Spring 的处理流程：</p><ol><li><p><strong>扫描注解</strong>：<br><code>ComponentScan</code> 扫描带有 <code>@Component</code>、<code>@Service</code> 等注解的类，注册为 <code>BeanDefinition</code>。</p></li><li><p><strong>解析依赖</strong>：<br><code>AutowiredAnnotationBeanPostProcessor</code> 在 Bean 实例化后，检查字段或方法上的 <code>@Autowired</code> 注解。</p></li><li><p><strong>依赖匹配</strong>：<br> 根据类型（<code>byType</code>）或名称（<code>byName</code>，结合 <code>@Qualifier</code>）从容器中查找匹配的 Bean。</p></li><li><p><strong>反射注入</strong>：<br> 通过反射设置依赖值。</p></li></ol><h3 id="_4-构造函数注入-vs-setter-注入" tabindex="-1"><a class="header-anchor" href="#_4-构造函数注入-vs-setter-注入"><span><strong>4. 构造函数注入 vs. Setter 注入</strong></span></a></h3><ul><li><p><strong>构造函数注入</strong>：<br> 通过构造函数提供依赖，确保对象创建后即处于完整状态，推荐用于必需依赖。</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java" data-title="java"><pre><code><span class="line"><span class="token keyword">public</span> <span class="token class-name">UserController</span><span class="token punctuation">(</span><span class="token class-name">UserService</span> userService<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">this</span><span class="token punctuation">.</span>userService <span class="token operator">=</span> userService<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p><strong>Setter 注入</strong>：<br> 通过 setter 方法提供依赖，适用于可选依赖。</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java" data-title="java"><pre><code><span class="line"><span class="token annotation punctuation">@Autowired</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">setUserService</span><span class="token punctuation">(</span><span class="token class-name">UserService</span> userService<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">this</span><span class="token punctuation">.</span>userService <span class="token operator">=</span> userService<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li></ul><h3 id="_5-spring-5-的改进-构造函数注入优先" tabindex="-1"><a class="header-anchor" href="#_5-spring-5-的改进-构造函数注入优先"><span><strong>5. Spring 5+ 的改进：构造函数注入优先</strong></span></a></h3><p>从 Spring 5 开始，推荐使用<strong>无 <code>@Autowired</code> 注解的构造函数注入</strong>：</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java" data-title="java"><pre><code><span class="line"><span class="token keyword">public</span> <span class="token class-name">UserController</span><span class="token punctuation">(</span><span class="token class-name">UserService</span> userService<span class="token punctuation">)</span> <span class="token punctuation">{</span> <span class="token comment">// 无需 @Autowired</span></span>
<span class="line">    <span class="token keyword">this</span><span class="token punctuation">.</span>userService <span class="token operator">=</span> userService<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><strong>优势</strong>： <ol><li>隐式标记必需依赖。</li><li>支持不可变对象（<code>final</code> 字段）。</li><li>防止循环依赖（编译时错误）。</li></ol></li></ul><h3 id="_6-循环依赖处理" tabindex="-1"><a class="header-anchor" href="#_6-循环依赖处理"><span><strong>6. 循环依赖处理</strong></span></a></h3><p>当 Bean A 依赖 Bean B，而 B 又依赖 A 时，Spring 通过<strong>三级缓存</strong>解决：</p><ol><li><strong>一级缓存</strong>（<code>singletonObjects</code>）：存储完全初始化的单例 Bean。</li><li><strong>二级缓存</strong>（<code>singletonFactories</code>）：存储早期暴露的 Bean 工厂（用于 AOP 代理）。</li><li><strong>三级缓存</strong>（<code>earlySingletonObjects</code>）：存储提前创建的原始 Bean 实例。</li></ol><p><strong>处理流程</strong>：</p><ol><li>创建 A 实例，将 A 的工厂放入三级缓存。</li><li>解析 A 的依赖 B，发现 B 未创建，开始创建 B。</li><li>创建 B 实例，将 B 的工厂放入三级缓存。</li><li>解析 B 的依赖 A，从三级缓存获取 A 的工厂，生成 A 的早期引用注入到 B。</li><li>B 完成初始化，放入一级缓存。</li><li>A 获取 B 的引用，完成初始化，放入一级缓存。</li></ol><h2 id="第三方的bean如何交给spring去管理" tabindex="-1"><a class="header-anchor" href="#第三方的bean如何交给spring去管理"><span>第三方的bean如何交给spring去管理？</span></a></h2><p><strong>回答：</strong></p><h4 id="一、注册第三方-bean-的方式" tabindex="-1"><a class="header-anchor" href="#一、注册第三方-bean-的方式"><span><strong>一、注册第三方 Bean 的方式</strong></span></a></h4><ol><li><p><strong><code>@Bean</code> 注解（最常用）</strong></p><ul><li>在 <code>@Configuration</code> 类中定义方法返回第三方组件实例。</li><li><strong>示例</strong>：<div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java" data-title="java"><pre><code><span class="line"><span class="token annotation punctuation">@Configuration</span>  </span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">AppConfig</span> <span class="token punctuation">{</span>  </span>
<span class="line">    <span class="token annotation punctuation">@Bean</span>  </span>
<span class="line">    <span class="token keyword">public</span> <span class="token class-name">RestTemplate</span> <span class="token function">restTemplate</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>  </span>
<span class="line">        <span class="token keyword">return</span> <span class="token keyword">new</span> <span class="token class-name">RestTemplate</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  </span>
<span class="line">    <span class="token punctuation">}</span>  </span>
<span class="line"><span class="token punctuation">}</span>  </span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li></ul></li><li><p><strong><code>@Import</code> 导入配置类</strong></p><ul><li>若第三方提供配置类，直接导入。</li><li><strong>示例</strong>：<div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java" data-title="java"><pre><code><span class="line"><span class="token annotation punctuation">@Import</span><span class="token punctuation">(</span><span class="token class-name">ThirdPartyConfig</span><span class="token punctuation">.</span><span class="token keyword">class</span><span class="token punctuation">)</span>  </span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">AppConfig</span> <span class="token punctuation">{</span><span class="token punctuation">}</span>  </span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div></li></ul></li><li><p><strong><code>FactoryBean</code> 接口</strong></p><ul><li>用于复杂组件的创建逻辑。</li><li><strong>示例</strong>：<div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java" data-title="java"><pre><code><span class="line"><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">MyFactoryBean</span> <span class="token keyword">implements</span> <span class="token class-name">FactoryBean</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">ThirdPartyClass</span><span class="token punctuation">&gt;</span></span> <span class="token punctuation">{</span>  </span>
<span class="line">    <span class="token comment">// 实现接口方法  </span></span>
<span class="line"><span class="token punctuation">}</span>  </span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li></ul></li><li><p><strong>自动配置（Spring Boot）</strong></p><ul><li>使用 <code>@ConditionalOnMissingBean</code> 提供默认实现。</li><li><strong>示例</strong>：<div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java" data-title="java"><pre><code><span class="line"><span class="token annotation punctuation">@Bean</span>  </span>
<span class="line"><span class="token annotation punctuation">@ConditionalOnMissingBean</span>  </span>
<span class="line"><span class="token keyword">public</span> <span class="token class-name">ThirdPartyClass</span> <span class="token function">thirdPartyClass</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>  </span>
<span class="line">    <span class="token keyword">return</span> <span class="token keyword">new</span> <span class="token class-name">ThirdPartyClass</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  </span>
<span class="line"><span class="token punctuation">}</span>  </span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li></ul></li><li><p><strong>XML 配置（兼容旧系统）</strong></p><ul><li>通过 <code>@ImportResource</code> 导入 XML 文件。</li><li><strong>示例</strong>：<div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java" data-title="java"><pre><code><span class="line"><span class="token annotation punctuation">@ImportResource</span><span class="token punctuation">(</span><span class="token string">&quot;classpath:thirdparty.xml&quot;</span><span class="token punctuation">)</span>  </span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div></li></ul></li></ol><h4 id="二、使用注册后的-bean" tabindex="-1"><a class="header-anchor" href="#二、使用注册后的-bean"><span><strong>二、使用注册后的 Bean</strong></span></a></h4><ol><li><p><strong>依赖注入（推荐）</strong></p><ul><li>通过构造函数或字段注入。</li><li><strong>示例</strong>：<div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java" data-title="java"><pre><code><span class="line"><span class="token annotation punctuation">@Service</span>  </span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">MyService</span> <span class="token punctuation">{</span>  </span>
<span class="line">    <span class="token keyword">private</span> <span class="token keyword">final</span> <span class="token class-name">RestTemplate</span> restTemplate<span class="token punctuation">;</span>  </span>
<span class="line"></span>
<span class="line">    <span class="token keyword">public</span> <span class="token class-name">MyService</span><span class="token punctuation">(</span><span class="token class-name">RestTemplate</span> restTemplate<span class="token punctuation">)</span> <span class="token punctuation">{</span>  </span>
<span class="line">        <span class="token keyword">this</span><span class="token punctuation">.</span>restTemplate <span class="token operator">=</span> restTemplate<span class="token punctuation">;</span>  </span>
<span class="line">    <span class="token punctuation">}</span>  </span>
<span class="line"><span class="token punctuation">}</span>  </span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li></ul></li><li><p><strong>通过 <code>ApplicationContext</code> 获取</strong></p><ul><li>在非 Spring 管理的类中手动获取。</li><li><strong>示例</strong>：<div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java" data-title="java"><pre><code><span class="line"><span class="token class-name">ApplicationContext</span> context <span class="token operator">=</span> <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">;</span>  </span>
<span class="line"><span class="token class-name">RestTemplate</span> restTemplate <span class="token operator">=</span> context<span class="token punctuation">.</span><span class="token function">getBean</span><span class="token punctuation">(</span><span class="token class-name">RestTemplate</span><span class="token punctuation">.</span><span class="token keyword">class</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  </span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div></li></ul></li><li><p><strong>在配置类内部使用</strong></p><ul><li>直接调用 <code>@Bean</code> 方法（Spring 确保返回单例）。</li><li><strong>示例</strong>：<div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java" data-title="java"><pre><code><span class="line"><span class="token annotation punctuation">@Configuration</span>  </span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">AppConfig</span> <span class="token punctuation">{</span>  </span>
<span class="line">    <span class="token annotation punctuation">@Bean</span>  </span>
<span class="line">    <span class="token keyword">public</span> <span class="token class-name">MyService</span> <span class="token function">myService</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>  </span>
<span class="line">        <span class="token keyword">return</span> <span class="token keyword">new</span> <span class="token class-name">MyService</span><span class="token punctuation">(</span><span class="token function">restTemplate</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  </span>
<span class="line">    <span class="token punctuation">}</span>  </span>
<span class="line"><span class="token punctuation">}</span>  </span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li></ul></li></ol><h4 id="三、关键区别" tabindex="-1"><a class="header-anchor" href="#三、关键区别"><span><strong>三、关键区别</strong></span></a></h4><table><thead><tr><th>场景</th><th>推荐方式</th><th>原因</th></tr></thead><tbody><tr><td><strong>自有类</strong></td><td><code>@Component</code></td><td>直接标记类，简单高效</td></tr><tr><td><strong>第三方类</strong></td><td><code>@Bean</code></td><td>无需修改源码，灵活配置</td></tr><tr><td><strong>复杂创建逻辑</strong></td><td><code>FactoryBean</code></td><td>封装复杂初始化过程</td></tr><tr><td><strong>Spring Boot</strong></td><td><code>@ConditionalOnMissingBean</code></td><td>自动配置，避免重复定义</td></tr></tbody></table><h4 id="四、注意事项" tabindex="-1"><a class="header-anchor" href="#四、注意事项"><span><strong>四、注意事项</strong></span></a></h4><ol><li><strong>单例作用域</strong>：默认 <code>@Bean</code> 创建的是单例 Bean，可通过 <code>@Scope</code> 修改。</li><li><strong>依赖顺序</strong>：<code>@Bean</code> 方法可通过参数注入依赖，Spring 自动处理顺序。</li><li><strong>避免循环依赖</strong>：构造函数注入时需注意依赖关系，优先使用 setter 注入。</li></ol>`,87)]))}const c=s(p,[["render",l]]),r=JSON.parse('{"path":"/series/knowledge/kuangjia/spring.html","title":"Spring","lang":"en-US","frontmatter":{"series":"框架","title":"Spring","order":1},"headers":[{"level":2,"title":"Spring、SpringBoot 的常用注解？","slug":"spring、springboot-的常用注解","link":"#spring、springboot-的常用注解","children":[{"level":3,"title":"1. 核心容器注解","slug":"_1-核心容器注解","link":"#_1-核心容器注解","children":[]},{"level":3,"title":"3. 事务管理注解","slug":"_3-事务管理注解","link":"#_3-事务管理注解","children":[]},{"level":3,"title":"4. Spring MVC 注解","slug":"_4-spring-mvc-注解","link":"#_4-spring-mvc-注解","children":[]},{"level":3,"title":"Spring Boot 常用注解","slug":"spring-boot-常用注解","link":"#spring-boot-常用注解","children":[]}]},{"level":2,"title":"什么是 Spring？它有哪些核心模块？","slug":"什么是-spring-它有哪些核心模块","link":"#什么是-spring-它有哪些核心模块","children":[]},{"level":2,"title":"什么是 IOC 和 AOP？","slug":"什么是-ioc-和-aop","link":"#什么是-ioc-和-aop","children":[]},{"level":2,"title":"AOP的常用的注解有哪些？实现原理？","slug":"aop的常用的注解有哪些-实现原理","link":"#aop的常用的注解有哪些-实现原理","children":[{"level":3,"title":"1. 常用注解","slug":"_1-常用注解","link":"#_1-常用注解","children":[]},{"level":3,"title":"2. 实现原理","slug":"_2-实现原理","link":"#_2-实现原理","children":[]},{"level":3,"title":"3. AOP 代理创建流程","slug":"_3-aop-代理创建流程","link":"#_3-aop-代理创建流程","children":[]},{"level":3,"title":"4. 关键组件","slug":"_4-关键组件","link":"#_4-关键组件","children":[]},{"level":3,"title":"5. AOP vs AspectJ","slug":"_5-aop-vs-aspectj","link":"#_5-aop-vs-aspectj","children":[]}]},{"level":2,"title":"Spring 是如何实现依赖注入的？底层是如何实现的？","slug":"spring-是如何实现依赖注入的-底层是如何实现的","link":"#spring-是如何实现依赖注入的-底层是如何实现的","children":[{"level":3,"title":"1. 依赖注入的基本概念","slug":"_1-依赖注入的基本概念","link":"#_1-依赖注入的基本概念","children":[]},{"level":3,"title":"2. Spring 依赖注入的底层实现","slug":"_2-spring-依赖注入的底层实现","link":"#_2-spring-依赖注入的底层实现","children":[]},{"level":3,"title":"3. 注解驱动的依赖注入（@Autowired）","slug":"_3-注解驱动的依赖注入-autowired","link":"#_3-注解驱动的依赖注入-autowired","children":[]},{"level":3,"title":"4. 构造函数注入 vs. Setter 注入","slug":"_4-构造函数注入-vs-setter-注入","link":"#_4-构造函数注入-vs-setter-注入","children":[]},{"level":3,"title":"5. Spring 5+ 的改进：构造函数注入优先","slug":"_5-spring-5-的改进-构造函数注入优先","link":"#_5-spring-5-的改进-构造函数注入优先","children":[]},{"level":3,"title":"6. 循环依赖处理","slug":"_6-循环依赖处理","link":"#_6-循环依赖处理","children":[]}]},{"level":2,"title":"第三方的bean如何交给spring去管理？","slug":"第三方的bean如何交给spring去管理","link":"#第三方的bean如何交给spring去管理","children":[]}],"git":{},"filePathRelative":"series/knowledge/框架/spring.md"}');export{c as comp,r as data};
